import org.apache.cxf.Bus;
import org.apache.cxf.BusFactory;
import org.apache.cxf.jaxws.EndpointImpl;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.wss4j.common.ConfigurationConstants;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

public class BankingServer {

    public static void main(String[] args) throws IOException {
        // Set up CXF bus (optional, but good practice for standalone servers)
        Bus bus = BusFactory.getDefaultBus();

        // This system property tells CXF to put the security context into the MessageContext
        // so it can be accessed by @Resource WebServiceContext in the service implementation.
        System.setProperty("javax.xml.ws.handler.MessageContext.SECURITY_CONTEXT", "org.apache.cxf.security.SecurityContext");

        // Create the service implementation
        BankingServiceImpl implementor = new BankingServiceImpl();

        // Create a JAX-WS endpoint with CXF's implementation
        EndpointImpl endpoint = new EndpointImpl(bus, implementor);

        // --- Configure WS-Security (Signature Verification) ---
        Map<String, Object> inProps = new HashMap<>();

        // 1. Specify the security actions for incoming messages
        //    'Signature' for verifying the XML signature
        //    'Timestamp' is good practice for freshness checks to prevent replay attacks
        inProps.put(ConfigurationConstants.ACTION, ConfigurationConstants.SIGNATURE + " " + ConfigurationConstants.TIMESTAMP);

        // 2. Specify the properties file for keystore/truststore configuration
        //    This file defines where the truststore is located, which contains
        //    the public certificates of trusted clients whose signatures we need to verify.
        //    The path is relative to the classpath (e.g., src/main/resources).
        inProps.put(ConfigurationConstants.SIG_PROP_FILE, "security.properties");

        // 3. Define how the signer's certificate is identified in the message.
        //    'DirectReference' means the signing certificate is embedded directly in the message.
        //    This is commonly used for client authentication signatures.
        inProps.put(ConfigurationConstants.SIG_KEY_ID, "DirectReference");

        // Optional: Specify signature algorithm if different from default, e.g.,
        // inProps.put(ConfigurationConstants.SIG_ALGO, WSConstants.RSA_SHA256);

        // Optional: If only specific elements of the SOAP body should be signed,
        // you can define them here. By default, WSS4J will verify the entire body
        // and any configured security headers like Timestamp.
        // Example to require the TransactionRequest element to be signed:
        // inProps.put(ConfigurationConstants.SIG_PARTS, "{Element}{http://ws.banking.mybank.com/}TransactionRequest;{}{" + WSConstants.WSU_NS + "}Timestamp");


        // Add the WSS4JInInterceptor to the inbound chain of the endpoint
        // This interceptor will process incoming messages, verify the signature and timestamp.
        WSS4JInInterceptor wssIn = new WSS4JInInterceptor(inProps);
        endpoint.getInInterceptors().add(wssIn);

        // --- Publish the service ---
        String address = "http://localhost:8080/bankingService";
        endpoint.publish(address);

        System.out.println("BankingService published at: " + address);
        System.out.println("WSDL available at: " + address + "?wsdl");
        System.out.println("Server ready. Press Enter to exit...");
        System.in.read();
        System.out.println("Server exiting.");
        endpoint.stop();
        System.exit(0);
    }
}
